import hashlib
# Initial implementation using Python's built in 'hashlib'. It is a pure python library and works across different versions of Pyhton 3 as well, providing cryptographic strength features such hashing algorithms. Here we use SHA-256 for simplicity but you can also choose other algorithm like MD5 or RIPEMD160 etc based on your requirement
def create_filehash(filename):  
    h = hashlib.sha256()  # Create a new sha object, defaulting to the SHA-256 hashing function in Python's 'hashlib'. This is an instance of HashObject which can be used for multiple times and also with different algorithms (like MD5)
    chunk_size = 8192   # Chunk size that will read from file at once. It should not exceed the system memory, otherwise it may cause OutOfMemoryError or even crash your program due to insufficient disk space if you are reading large files in chunks 
    
    with open(filename,'rb') as f:      # Opening a binary mode 'r' file for hashing. The b flag is used because the filename passed into this function might be unicode and it needs bytes, not str type data to work properly (like Python3). This will also handle large files efficiently
        while True: 
            c = f.read(chunk_size)   # Read a chunk of file at once from disk in binary mode 'rb' which is readable by the system and can be used for multiple times, it returns bytes object if end-of-file (EOF), else None type data will come out
            if not c:  break    # If there are no more chunks to process then exit loop. This means that we have reached EOF of file which is the point where 'while True' stops executing and hence, it breaks from while block in python as well (break statement)  
            
            h.update(c)  # Update hash object with chunk data read so far for hashing process to be secure against side-channel attacks or other types of attackers who can manipulate the input by changing bits inside a message, this is done using 'h.update()' method which accepts bytes type and updates internal state
    
    return h.hexdigest()  # Return hexadecimal representation (hash) string after all chunks have been processed from file